sql:
SELECT COUNT(DISTINCT team_home_id) 
FROM games 
WHERE team_home_id IS NOT NULL;

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE schedule_week = 21 AND schedule_playoff = 1;

external_knowledge:
- 'behavior issues' refers to penalties; 
- 'preliminary games' refers to games in the 'preseason' type of season; 
- 'audience' refers to the attendance at the games.

sql:
SELECT AVG(penalties_per_game) as avg_penalties
FROM (
  SELECT game_id, COUNT(*) as penalties_per_game
  FROM penalties
  GROUP BY game_id
);

SELECT game_id, attendance
FROM games
WHERE stadium_id = (
    SELECT stadium_id 
    FROM stadiums 
    WHERE capacity = (
        SELECT MAX(capacity) 
        FROM stadiums
    )
) AND schedule_week = 15 AND schedule_season = 2019;

SELECT COUNT(DISTINCT user_id)
FROM access_logs
WHERE access_type = 'view' AND game_id IN (SELECT game_id FROM game_stats);
